export const ALL_LLQP = [
  // --- LIFE INSURANCE ---
  { topic: "Life Insurance", question: "What is the primary difference between Term and Whole Life insurance?", options: ["Term covers illness; Whole Life covers death", "Term is for a specific period with no cash value; Whole Life is permanent with a cash surrender value", "Term is more expensive initially", "Whole Life expires at age 65"], answer: "Term is for a specific period with no cash value; Whole Life is permanent with a cash surrender value", explanation: "Term is 'pure insurance' for a set time (e.g., 10 or 20 years). Whole Life lasts until death and builds an investment component (cash value)." },
  { topic: "Life Insurance", question: "What happens if a policyholder stops paying premiums on a Universal Life policy?", options: ["The policy is immediately cancelled", "The policy continues as long as there is sufficient cash value to cover the monthly mortality and administrative charges", "The death benefit is cut in half", "The insurer will sue for the balance"], answer: "The policy continues as long as there is sufficient cash value to cover the monthly mortality and administrative charges", explanation: "Universal Life is flexible. Monthly deductions are taken from the investment account. If the account hits zero, the policy lapses." },
  { topic: "Life Insurance", question: "If the insured commits suicide 6 months after a life insurance policy is issued, the insurer will:", options: ["Pay the full death benefit", "Deny the claim and refund the premiums paid", "Pay 50% of the benefit", "Keep the premiums and pay nothing"], answer: "Deny the claim and refund the premiums paid", explanation: "Standard life policies have a 2-year suicide exclusion. If suicide occurs within 2 years, the benefit is denied but premiums are returned." },
  { topic: "Life Insurance", question: "An 'Irrevocable Beneficiary' means:", options: ["The beneficiary cannot be changed under any circumstances", "The beneficiary can only be changed with their written consent", "The beneficiary is a minor", "The beneficiary is the insured's estate"], answer: "The beneficiary can only be changed with their written consent", explanation: "Unlike a revocable beneficiary, an irrevocable beneficiary has vested rights in the policy and must consent to changes or policy loans." },
  { topic: "Life Insurance", question: "What is the 'Incontestability' provision?", options: ["The insured cannot cancel the policy", "After the policy has been in force for 2 years, the insurer cannot void it for misrepresentation or concealment, except for outright fraud", "The beneficiary cannot contest the payout amount", "The premium can never be increased"], answer: "After the policy has been in force for 2 years, the insurer cannot void it for misrepresentation or concealment, except for outright fraud", explanation: "This protects the beneficiaries from having a claim denied years later for a minor, innocent mistake on the original application." },
  { topic: "Life Insurance", question: "A 'Waiver of Premium' rider does what?", options: ["Waives the first month's premium", "Waives premiums if the insured becomes totally disabled, keeping the policy in force", "Allows the insured to skip payments at Christmas", "Waives the premium after age 65"], answer: "Waives premiums if the insured becomes totally disabled, keeping the policy in force", explanation: "It acts as disability insurance for the life insurance policy itself." },
  { topic: "Life Insurance", question: "When a life insurance policy is 'Collaterally Assigned', it is being used to:", options: ["Change the beneficiary", "Transfer ownership to a child", "Secure a loan with a lender (e.g., a bank)", "Pay for funeral expenses in advance"], answer: "Secure a loan with a lender (e.g., a bank)", explanation: "Collateral assignment pledges the death benefit (or cash value) to a creditor to secure a debt." },
  { topic: "Life Insurance", question: "If an applicant misstates their age on a life application (saying they are younger to get a better rate), how does the insurer handle a death claim?", options: ["Denies the claim entirely", "Adjusts the death benefit to what the premium paid would have purchased at the correct age", "Pays the full amount but fines the beneficiary", "Cancels the policy retroactively"], answer: "Adjusts the death benefit to what the premium paid would have purchased at the correct age", explanation: "Misstatement of age is an exception to incontestability. The benefit is simply mathematically adjusted, not voided." },
  { topic: "Life Insurance", question: "What is a 'Renewable and Convertible' Term policy?", options: ["It renews without medical evidence and can be converted to permanent insurance without medical evidence", "It renews at the same price forever", "It can be converted into auto insurance", "It automatically converts to Whole Life after 1 year"], answer: "It renews without medical evidence and can be converted to permanent insurance without medical evidence", explanation: "These features allow a client whose health has declined to maintain or upgrade coverage without taking a new medical exam." },
  { topic: "Life Insurance", question: "Key Person insurance is purchased by a business to:", options: ["Provide a retirement fund for the CEO", "Compensate the business for the financial loss and disruption caused by the death of a crucial employee", "Pay the key employee's family", "Cover workers compensation claims"], answer: "Compensate the business for the financial loss and disruption caused by the death of a crucial employee", explanation: "The business is the owner, premium payer, and beneficiary of the policy." },
  { topic: "Life Insurance", question: "Joint Last-to-Die (Survivorship) life insurance is primarily used for:", options: ["Paying off a mortgage", "Income replacement for a young family", "Estate preservation and paying capital gains taxes upon the death of the second spouse", "Funding a child's education"], answer: "Estate preservation and paying capital gains taxes upon the death of the second spouse", explanation: "Since tax liabilities often defer to the surviving spouse, the tax bill hits when the second spouse dies. This policy provides the liquidity to pay it." },
  { topic: "Life Insurance", question: "Under a Participating (Par) Whole Life policy, dividends are:", options: ["Guaranteed by law", "A return of overcharged premium based on the insurer's favorable mortality, interest, and expense experience", "Taxable as capital gains", "Paid only upon death"], answer: "A return of overcharged premium based on the insurer's favorable mortality, interest, and expense experience", explanation: "Dividends are not guaranteed. They are essentially a refund of excess premiums if the insurer performs well." },
  { topic: "Life Insurance", question: "The 'Grace Period' in a life insurance policy is usually:", options: ["10 days", "30 or 31 days", "60 days", "90 days"], answer: "30 or 31 days", explanation: "The grace period prevents immediate lapse. If the insured dies during this period, the overdue premium is deducted from the death benefit." },
  { topic: "Life Insurance", question: "A Guaranteed Insurability Benefit (GIB) rider allows the insured to:", options: ["Stop paying premiums", "Purchase additional insurance at specified future dates or life events without medical evidence", "Guarantee an 8% return on cash value", "Withdraw cash penalty-free"], answer: "Purchase additional insurance at specified future dates or life events without medical evidence", explanation: "This is critical for young clients whose insurance needs will grow (marriage, kids) regardless of future health issues." },
  { topic: "Life Insurance", question: "What is the primary tax advantage of the death benefit of a personal life insurance policy?", options: ["It is tax-deductible to the payer", "It is received tax-free by the beneficiary", "It generates a tax credit", "It reduces capital gains on other assets"], answer: "It is received tax-free by the beneficiary", explanation: "In Canada, life insurance death benefits paid to a named beneficiary are generally tax-free." },
  { topic: "Life Insurance", question: "What does 'Absolute Assignment' of a life insurance policy mean?", options: ["Using the policy for a bank loan", "The complete and permanent transfer of all ownership rights to another party", "Naming a new beneficiary", "Converting a term policy to whole life"], answer: "The complete and permanent transfer of all ownership rights to another party", explanation: "Unlike collateral assignment (which is temporary for a loan), absolute assignment makes the assignee the new permanent owner." },
  { topic: "Life Insurance", question: "A 'Paid-Up Additions' (PUA) dividend option allows the policyholder to:", options: ["Get a cash cheque every year", "Use their dividends to buy small blocks of fully paid permanent life insurance, increasing the total death benefit and cash value", "Pay off their mortgage", "Reduce their monthly premium"], answer: "Use their dividends to buy small blocks of fully paid permanent life insurance, increasing the total death benefit and cash value", explanation: "PUAs compound over time, making it an excellent long-term strategy for maximizing a participating whole life policy." },
  { topic: "Life Insurance", question: "What is the 'Reinstatement' provision?", options: ["Allows an insured to get their job back after disability", "Allows a policyowner to restore a lapsed policy within a certain time (usually 2 years) by paying back premiums plus interest and proving good health", "Allows a beneficiary to be changed after death", "Restores a cancelled driver's license"], answer: "Allows a policyowner to restore a lapsed policy within a certain time (usually 2 years) by paying back premiums plus interest and proving good health", explanation: "Reinstatement keeps the original age and premium rate, but requires fresh medical underwriting to prove the insured is still insurable." },
  { topic: "Life Insurance", question: "In a 'Joint First-to-Die' policy, what happens when the first insured person dies?", options: ["The policy pays 50% of the benefit", "The policy pays the full death benefit and then terminates", "The policy continues for the survivor", "The premiums double for the survivor"], answer: "The policy pays the full death benefit and then terminates", explanation: "These are often used for mortgage protection or business partners, paying out immediately upon the first death." },
  { topic: "Life Insurance", question: "What is a 'Level Term' policy?", options: ["The premium increases every month", "The death benefit remains the same for the duration of the term, but the premium increases at renewal", "The death benefit decreases as a mortgage is paid off", "It covers level ground"], answer: "The death benefit remains the same for the duration of the term, but the premium increases at renewal", explanation: "A 20-Year Level Term policy guarantees a constant $500k payout for 20 years. After 20 years, the death benefit stays the same, but the cost to renew skyrockets." },

  // --- ACCIDENT & SICKNESS ---
  { topic: "Accident & Sickness", question: "In Disability Insurance, 'Own Occupation' definition of disability means the insured is considered disabled if:", options: ["They cannot perform any job whatsoever", "They cannot perform the essential duties of their specific regular occupation", "They are confined to a hospital", "They suffer a 50% loss of income"], answer: "They cannot perform the essential duties of their specific regular occupation", explanation: "Even if they could work in a different field (e.g., a surgeon becoming a teacher), they still receive full benefits under 'Own Occ'." },
  { topic: "Accident & Sickness", question: "The 'Elimination Period' (Waiting Period) in a disability policy acts as:", options: ["A time limit to file a claim", "A time deductible; the period the insured must be disabled before benefits begin to accrue", "The length of time benefits are paid", "A probationary period for new illnesses"], answer: "A time deductible; the period the insured must be disabled before benefits begin to accrue", explanation: "Choosing a longer elimination period (e.g., 90 days vs 30 days) significantly lowers the premium." },
  { topic: "Accident & Sickness", question: "A Critical Illness (CI) policy pays a lump sum benefit when:", options: ["The insured dies", "The insured is unable to work for 6 months", "The insured survives a specified waiting period (usually 30 days) after being diagnosed with a covered condition like Cancer, Stroke, or Heart Attack", "The insured incurs medical bills"], answer: "The insured survives a specified waiting period (usually 30 days) after being diagnosed with a covered condition like Cancer, Stroke, or Heart Attack", explanation: "CI pays a tax-free lump sum upon survival of the diagnosis, regardless of whether the insured can still work." },
  { topic: "Accident & Sickness", question: "What is 'Integration of Benefits' in a group disability plan?", options: ["Combining life and health insurance", "Reducing the insurer's disability payout by the amount the insured receives from other sources (like CPP or WSIB)", "Paying double benefits if both spouses work", "Allowing the employee to upgrade their plan"], answer: "Reducing the insurer's disability payout by the amount the insured receives from other sources (like CPP or WSIB)", explanation: "Integration ensures the disabled person does not earn more while disabled than they did while working (the all-source maximum)." },
  { topic: "Accident & Sickness", question: "Long-Term Care (LTC) insurance triggers benefits when the insured:", options: ["Reaches age 65", "Is unable to perform a certain number of Activities of Daily Living (ADLs) or suffers cognitive impairment", "Retires", "Is diagnosed with a terminal illness"], answer: "Is unable to perform a certain number of Activities of Daily Living (ADLs) or suffers cognitive impairment", explanation: "ADLs include bathing, dressing, eating, transferring, toileting, and continence. Inability to perform 2 usually triggers the claim." },
  { topic: "Accident & Sickness", question: "If an employee pays 100% of the premium for their Group Long-Term Disability (LTD) coverage, the benefits received are:", options: ["Taxable as regular income", "Tax-free to the employee", "Subject to capital gains tax", "Only taxable if they exceed $5,000/month"], answer: "Tax-free to the employee", explanation: "If the employee pays the premium with after-tax dollars, the resulting disability benefit is tax-free. If the employer pays, the benefit is taxable." },
  { topic: "Accident & Sickness", question: "A 'Non-Cancellable' disability policy means the insurer:", options: ["Cannot cancel the policy and cannot raise the premium for the life of the contract", "Cannot cancel but can raise the premium for the entire class of insureds", "Will refund premiums if no claims are made", "Guarantees employment"], answer: "Cannot cancel the policy and cannot raise the premium for the life of the contract", explanation: "This is the highest quality (and most expensive) form of disability insurance. 'Guaranteed Renewable' allows rate increases; Non-Can does not." },
  { topic: "Accident & Sickness", question: "What is a 'Presumptive Disability'?", options: ["A condition assumed to happen eventually", "A severe loss (like sight, speech, hearing, or two limbs) where the insured is presumed totally disabled even if they can still work", "A disability caused by a pre-existing condition", "A short-term cold"], answer: "A severe loss (like sight, speech, hearing, or two limbs) where the insured is presumed totally disabled even if they can still work", explanation: "Benefits are paid immediately without waiting periods and continue even if the insured returns to work." },
  { topic: "Accident & Sickness", question: "Under a Return of Premium (ROP) rider on a Critical Illness policy:", options: ["The insured gets their money back if they cancel in the first 10 days", "A portion or all of the premiums are refunded if the insured dies or the policy matures without a claim", "The broker must refund their commission", "The government refunds the tax paid"], answer: "A portion or all of the premiums are refunded if the insured dies or the policy matures without a claim", explanation: "ROP acts as a forced savings plan; if you stay healthy, you get your premiums back." },
  { topic: "Accident & Sickness", question: "A Business Overhead Expense (BOE) disability policy covers:", options: ["The disabled owner's salary", "Lost profits of the business", "Fixed ongoing expenses of the business (rent, utilities, employee salaries) while the owner is disabled", "The cost to hire a replacement"], answer: "Fixed ongoing expenses of the business (rent, utilities, employee salaries) while the owner is disabled", explanation: "BOE keeps the lights on while the owner recovers. It explicitly does *not* cover the owner's own salary or loss of profit." },
  { topic: "Accident & Sickness", question: "Which ADL (Activity of Daily Living) refers to the ability to move in and out of a bed or chair?", options: ["Mobility", "Transferring", "Ambulating", "Positioning"], answer: "Transferring", explanation: "Transferring is a standard ADL used to assess physical independence for Long Term Care claims." },
  { topic: "Accident & Sickness", question: "If a disability policy defines total disability as 'Any Occupation', it means:", options: ["The insured can work any job they want", "The insured is disabled only if they cannot perform duties of any job they are reasonably suited for by education, training, or experience", "The insurer will train them for a new job", "They must be bedridden"], answer: "The insured is disabled only if they cannot perform duties of any job they are reasonably suited for by education, training, or experience", explanation: "This is a stricter definition than 'Own Occ'. If a disabled surgeon can comfortably teach biology, they are not disabled under 'Any Occ'." },
  { topic: "Accident & Sickness", question: "What is a 'Partial Disability' benefit?", options: ["Pays 50% of the benefit for the rest of their life", "Pays a reduced benefit if the insured can only work part-time or perform some, but not all, of their duties", "Covers the loss of one eye", "Only covers mental illness"], answer: "Pays a reduced benefit if the insured can only work part-time or perform some, but not all, of their duties", explanation: "It encourages recovery and returning to work by topping up the lost income." },
  { topic: "Accident & Sickness", question: "Key Person Disability insurance benefits are usually paid to:", options: ["The disabled employee", "The employee's family", "The business", "The government"], answer: "The business", explanation: "The business owns the policy to protect itself from the financial hit of losing the key employee's productivity." },
  { topic: "Accident & Sickness", question: "What is a Buy-Sell agreement funded by Disability Insurance?", options: ["A contract for the business to buy new equipment", "An agreement providing funds for healthy partners to buy out a disabled partner's share of the business", "A stock market strategy", "A policy that pays off business loans"], answer: "An agreement providing funds for healthy partners to buy out a disabled partner's share of the business", explanation: "If a partner is permanently disabled, the policy provides a lump sum or series of payments so the remaining partners can buy their shares." },
  { topic: "Accident & Sickness", question: "What is the 'Future Income Option' (FIO) or 'Guaranteed Insurability' rider on a disability policy?", options: ["It guarantees the stock market will go up", "It allows the insured to increase their monthly disability benefit in the future as their income grows, without providing new medical evidence", "It pays out when they retire", "It covers future children"], answer: "It allows the insured to increase their monthly disability benefit in the future as their income grows, without providing new medical evidence", explanation: "A young doctor buying disability needs to ensure they can increase coverage later when they are making triple their starting salary, even if their health declines." },
  { topic: "Accident & Sickness", question: "What is 'Residual Disability'?", options: ["A permanent physical scar", "A benefit based on the percentage of income lost due to a disability, rather than specific time missed", "Disability caused by chemical residue", "A completely excluded condition"], answer: "A benefit based on the percentage of income lost due to a disability, rather than specific time missed", explanation: "If you return to work but can only see half as many clients, resulting in a 40% income drop, the residual benefit pays 40% of your policy limit." },
  { topic: "Accident & Sickness", question: "A 'Pre-existing Condition' exclusion usually applies for how long after a policy is issued?", options: ["Forever", "Typically 12 to 24 months, meaning any condition diagnosed or treated prior to the application won't be covered if it flares up during this period", "30 days", "Until age 65"], answer: "Typically 12 to 24 months, meaning any condition diagnosed or treated prior to the application won't be covered if it flares up during this period", explanation: "It protects insurers from people who feel a lump and immediately try to buy Critical Illness insurance." },
  { topic: "Accident & Sickness", question: "What does the 'Coordination of Benefits' (COB) provision do in group health/dental plans?", options: ["Dictates which doctors you can see", "Determines which plan pays first when an employee is covered by two plans (e.g., their own and their spouse's)", "Coordinates physical therapy", "Cancels duplicate policies"], answer: "Determines which plan pays first when an employee is covered by two plans (e.g., their own and their spouse's)", explanation: "COB prevents 'double dipping'. Your own plan pays first, and your spouse's plan can top up the remainder." },

  // --- SEGREGATED FUNDS & ANNUITIES ---
  { topic: "Segregated Funds", question: "A primary feature of a Segregated Fund that distinguishes it from a Mutual Fund is:", options: ["Lower MERs (Management Expense Ratios)", "Guarantees on the principal amount at maturity and death (usually 75% to 100%)", "Higher risk potential", "They only invest in government bonds"], answer: "Guarantees on the principal amount at maturity and death (usually 75% to 100%)", explanation: "Because Seg Funds are technically insurance contracts, they offer principal protection guarantees." },
  { topic: "Segregated Funds", question: "To qualify for the Maturity Guarantee in a Segregated Fund, the money must typically remain invested for:", options: ["1 year", "5 years", "10 years", "Until age 65"], answer: "10 years", explanation: "The standard maturity period for the 75% or 100% guarantee is 10 years." },
  { topic: "Segregated Funds", question: "What is a 'Reset' feature in a Segregated Fund?", options: ["Erasing the investment history", "Locking in market gains to increase the guaranteed amount, which also restarts the 10-year maturity clock", "Changing the fund manager", "Resetting the MER to zero"], answer: "Locking in market gains to increase the guaranteed amount, which also restarts the 10-year maturity clock", explanation: "If a $100k investment grows to $150k, the client can 'reset' the guarantee so their new protected floor is based on $150k." },
  { topic: "Segregated Funds", question: "Because a Segregated Fund is an insurance contract, naming a beneficiary allows the funds to:", options: ["Grow tax-free", "Bypass probate and go directly to the beneficiary upon death", "Be withdrawn penalty-free at any time", "Be immune to market drops"], answer: "Bypass probate and go directly to the beneficiary upon death", explanation: "Bypassing probate saves the estate significant time, legal fees, and probate taxes (Estate Administration Tax)." },
  { topic: "Segregated Funds", question: "In the event of an insurance company's insolvency, Segregated Funds are protected by:", options: ["CDIC (Canada Deposit Insurance Corporation)", "CIPF (Canadian Investor Protection Fund)", "Assuris", "The Bank of Canada"], answer: "Assuris", explanation: "Assuris protects Canadian life insurance policyholders (including seg funds) against the failure of their life insurance company." },
  { topic: "Segregated Funds", question: "Creditor protection is a major advantage of Segregated Funds. When is this protection generally valid?", options: ["Always, automatically", "When a preferred or irrevocable beneficiary is named (like a spouse or child), and the investment wasn't made to defraud creditors", "Only for corporate accounts", "Only if the fund is losing money"], answer: "When a preferred or irrevocable beneficiary is named (like a spouse or child), and the investment wasn't made to defraud creditors", explanation: "The insurance structure can shield the asset from bankruptcy or lawsuits, provided the beneficiary designation qualifies." },
  { topic: "Segregated Funds", question: "The allocation of capital gains/losses in a Segregated Fund is:", options: ["Done when the client withdraws the money", "Allocated directly to the investor each year, allowing them to claim the exact tax treatment on their personal return", "Tax-free forever", "Paid by the insurance company"], answer: "Allocated directly to the investor each year, allowing them to claim the exact tax treatment on their personal return", explanation: "Unlike mutual funds, seg funds use 'allocations' so the tax character of the income (dividends, capital gains) flows cleanly to the investor." },
  { topic: "Segregated Funds", question: "Who regulates the sale of Segregated Funds?", options: ["Provincial Securities Commissions", "Provincial Insurance Regulators", "The Federal Government", "The local municipality"], answer: "Provincial Insurance Regulators", explanation: "Because they are Individual Variable Insurance Contracts (IVICs), they fall under insurance regulation, not securities." },
  { topic: "Segregated Funds", question: "A 'Death Guarantee' in a Seg Fund ensures:", options: ["The beneficiary receives the higher of the market value or the guaranteed amount (e.g., 75% or 100% of deposits)", "The beneficiary receives double the deposit", "Death benefits are tax-deductible", "The fund cannot lose value while the insured is alive"], answer: "The beneficiary receives the higher of the market value or the guaranteed amount (e.g., 75% or 100% of deposits)", explanation: "If the market crashes right before the annuitant dies, the beneficiary is protected by the guaranteed floor." },
  { topic: "Segregated Funds", question: "What is the typical MER (Management Expense Ratio) comparison?", options: ["Seg funds are usually cheaper than mutual funds", "Seg funds are typically higher than mutual funds to pay for the insurance guarantees", "They are exactly the same by law", "Seg funds have no MER"], answer: "Seg funds are typically higher than mutual funds to pay for the insurance guarantees", explanation: "The cost of the maturity and death guarantees is built into the slightly higher MER of a segregated fund." },
  { topic: "Segregated Funds", question: "What is a 'Life Annuity'?", options: ["A temporary bank loan", "An insurance contract that pays a guaranteed stream of income to the annuitant for the rest of their life", "A policy that only pays upon death", "A stock market index fund"], answer: "An insurance contract that pays a guaranteed stream of income to the annuitant for the rest of their life", explanation: "Annuities protect against the risk of 'living too long' and outliving your savings." },
  { topic: "Segregated Funds", question: "In an annuity, what is a 'Guarantee Period' (e.g., Life with a 10-Year Guarantee)?", options: ["The annuity only pays for 10 years and stops", "If the annuitant dies within the first 10 years, the payments continue to a beneficiary until the 10 years are up", "The interest rate is guaranteed for 10 years", "The annuitant is guaranteed to live 10 years"], answer: "If the annuitant dies within the first 10 years, the payments continue to a beneficiary until the 10 years are up", explanation: "If the annuitant lives 25 years, it pays for 25 years. If they die in year 2, the beneficiary gets the remaining 8 years of payments." },
  { topic: "Segregated Funds", question: "Who takes on the investment and mortality risk in a fixed life annuity?", options: ["The Annuitant", "The Insurance Company", "The Beneficiary", "The Government"], answer: "The Insurance Company", explanation: "Once the premium is paid, the insurer guarantees the payout, absorbing all the risk if the market crashes or the person lives to 110." },
  { topic: "Segregated Funds", question: "When purchasing a non-registered annuity, what is the tax advantage of a 'Prescribed Annuity'?", options: ["It is 100% tax-free", "It levels out the taxable interest portion of each payment so the tax hit is completely uniform over the life of the contract", "It generates a capital loss", "It avoids probate"], answer: "It levels out the taxable interest portion of each payment so the tax hit is completely uniform over the life of the contract", explanation: "Standard annuities front-load the taxable interest. Prescribed annuities spread it out evenly, which is much better for seniors." },

  // --- ETHICS, TAX & LEGAL ---
  { topic: "Ethics & Legal", question: "Under FINTRAC (Anti-Money Laundering rules), a life agent must keep a 'Large Cash Transaction Record' if a client pays with cash amounting to:", options: ["$1,000 or more", "$5,000 or more", "$10,000 or more", "$50,000 or more"], answer: "$10,000 or more", explanation: "Life insurance products (especially Universal Life and annuities) are prime targets for money laundering. Cash over $10k must be reported." },
  { topic: "Ethics & Legal", question: "What is 'Churning' or 'Twisting'?", options: ["Mixing trust funds with operating funds", "Convincing a client to cancel an existing policy to buy a new one solely to generate a new commission for the agent, to the client's detriment", "Selling mutual funds without a license", "Failing to deliver a policy document"], answer: "Convincing a client to cancel an existing policy to buy a new one solely to generate a new commission for the agent, to the client's detriment", explanation: "This is a severe ethical violation. Replacements must always be in the best interest of the client and require a Life Insurance Replacement Declaration (LIRD)." },
  { topic: "Ethics & Legal", question: "If a life insurance policy is transferred to a corporation for business purposes, what tax concept must be evaluated?", options: ["Capital Cost Allowance", "Adjusted Cost Basis (ACB) and potential disposition", "Sales tax (HST)", "Property tax"], answer: "Adjusted Cost Basis (ACB) and potential disposition", explanation: "Transferring a policy can trigger a taxable event (a disposition) if the cash surrender value or fair market value exceeds the ACB." },
  { topic: "Ethics & Legal", question: "What is 'Fronting'?", options: ["Putting the client's name first on the application", "An unlicensed person soliciting business and having a licensed agent sign the paperwork as if they made the sale", "Paying the first month's premium for the client", "A marketing strategy"], answer: "An unlicensed person soliciting business and having a licensed agent sign the paperwork as if they made the sale", explanation: "Fronting bypasses regulatory licensing requirements and is illegal for both the licensed and unlicensed party." },
  { topic: "Ethics & Legal", question: "A Life Insurance Replacement Declaration (LIRD) is required when:", options: ["A client updates their address", "A client changes their beneficiary", "An existing life insurance policy is being cancelled or altered to make way for a new policy", "A client dies"], answer: "An existing life insurance policy is being cancelled or altered to make way for a new policy", explanation: "The LIRD forces a strict comparison of the old vs. new policy to ensure the client understands what they are giving up." },
  { topic: "Ethics & Legal", question: "A 10-day 'Free Look' or 'Right of Rescission' period means:", options: ["The agent doesn't get paid for 10 days", "The client can review the delivered policy for 10 days and cancel for a full refund if not satisfied", "The insurer has 10 days to deny the application", "The medical exam is valid for 10 days"], answer: "The client can review the delivered policy for 10 days and cancel for a full refund if not satisfied", explanation: "This gives consumers a cooling-off period to review the complex legal contract." },
  { topic: "Ethics & Legal", question: "Tied selling is illegal. Which is an example of tied selling?", options: ["A bank saying 'We will only approve your mortgage if you buy life insurance from us'", "A broker offering a discount for buying both home and auto", "Suggesting a client buy disability along with life insurance", "Recommending a segregated fund"], answer: "A bank saying 'We will only approve your mortgage if you buy life insurance from us'", explanation: "Coercing a client to buy product B as a mandatory condition of getting product A is illegal tied selling." },
  { topic: "Ethics & Legal", question: "What happens to the death benefit if a policy is deemed 'Exempt' under the Income Tax Act?", options: ["It is heavily taxed", "It remains tax-free to the beneficiary, and the internal cash value grows tax-sheltered", "It must be paid to the government", "It can only be paid to a charity"], answer: "It remains tax-free to the beneficiary, and the internal cash value grows tax-sheltered", explanation: "Most standard life policies are designed to be 'MTAR Exempt' so the investment growth inside the policy isn't taxed annually." },
  { topic: "Ethics & Legal", question: "Who holds the rights to change the beneficiary, borrow against the policy, or cancel it?", options: ["The Life Insured", "The Beneficiary", "The Policy Owner", "The Agent"], answer: "The Policy Owner", explanation: "The Owner controls the contract. The Insured is merely the life upon which the contract is based (often the same person, but not always)." },
  { topic: "Ethics & Legal", question: "In a corporate-owned life insurance policy, what is the Capital Dividend Account (CDA)?", options: ["An expense account for the CEO", "A notional tax account that allows the tax-free death benefit to flow out of the corporation to shareholders tax-free", "A bank account for premiums", "A government tax penalty"], answer: "A notional tax account that allows the tax-free death benefit to flow out of the corporation to shareholders tax-free", explanation: "The CDA is the crucial mechanism that preserves the tax-free nature of life insurance when the money moves from the corporation to the surviving owners." },
  { topic: "Ethics & Legal", question: "Which of the following describes 'Rebating'?", options: ["Refunding an overpaid premium", "An agent giving a client $500 of their commission as an incentive to buy a policy", "Providing a free calendar with the agency logo", "Canceling a policy in the first 10 days"], answer: "An agent giving a client $500 of their commission as an incentive to buy a policy", explanation: "Rebating is strictly illegal. Inducing a client to buy with cash or gifts violates market fairness." },
  { topic: "Ethics & Legal", question: "What is a 'Temporary License' in the life insurance industry?", options: ["A license for summer students", "Some provinces issue a short-term license (e.g., 6 months) allowing new agents to work under strict supervision while finishing their exams", "A license to sell auto insurance", "A license that does not require an exam"], answer: "Some provinces issue a short-term license (e.g., 6 months) allowing new agents to work under strict supervision while finishing their exams", explanation: "Not all provinces offer this, but it is designed for training purposes and requires a sponsoring agent to take full responsibility." },
  { topic: "Ethics & Legal", question: "Under PIPEDA, how long must an agent retain client personal information?", options: ["Forever", "Only as long as necessary to fulfill the purpose for which it was collected, and to meet legal/regulatory requirements", "5 years max", "Until the client dies"], answer: "Only as long as necessary to fulfill the purpose for which it was collected, and to meet legal/regulatory requirements", explanation: "Hoarding data indefinitely violates privacy laws. Records must be securely destroyed when no longer legally needed." },
  { topic: "Ethics & Legal", question: "If a life agent wants to advertise themselves as a 'Financial Planner', they generally must:", options: ["Have 5 years of experience", "Hold a specific recognized designation (like CFP or PFP) in addition to their life license", "Ask the insurer for permission", "Sell segregated funds"], answer: "Hold a specific recognized designation (like CFP or PFP) in addition to their life license", explanation: "Regulators crack down on agents falsely using titles that imply complex financial planning expertise without the actual credentials." },
  { topic: "Ethics & Legal", question: "A 'Letter of Direction' is used by a client to:", options: ["Apply for a job", "Formally authorize an agent to request information from another financial institution or insurer on their behalf", "Cancel their driver's license", "Borrow money from the bank"], answer: "Formally authorize an agent to request information from another financial institution or insurer on their behalf", explanation: "Privacy laws require written authorization before an insurer will release policy details to a new agent." },
  { topic: "Ethics & Legal", question: "What constitutes 'Defamation' in the insurance industry?", options: ["Canceling a client's policy", "Making false, malicious statements designed to injure the reputation of a competitor or competing insurer", "Selling term instead of whole life", "Charging a broker fee"], answer: "Making false, malicious statements designed to injure the reputation of a competitor or competing insurer", explanation: "Agents must compete on their own merits, not by spreading lies that a competitor is going bankrupt." },
  { topic: "Ethics & Legal", question: "When delivering a new policy, an agent realizes the client's health has deteriorated significantly since the application. The agent must:", options: ["Deliver the policy immediately", "Refuse to deliver the policy and notify the insurer, as the health change is a material fact", "Double the premium", "Tell the client not to mention it"], answer: "Refuse to deliver the policy and notify the insurer, as the health change is a material fact", explanation: "Coverage only binds if the insured is in the same state of health upon delivery as they were upon application." },
// --- BATCH 3: ADVANCED LIFE & TAXATION ---
  { topic: "Life Insurance", question: "If a policyholder forgets to pay their premium and the grace period expires, what keeps a Whole Life policy from lapsing if it has cash value?", options: ["The Incontestability Clause", "The Automatic Premium Loan (APL) provision", "The Waiver of Premium rider", "The Guarantor"], answer: "The Automatic Premium Loan (APL) provision", explanation: "APL automatically borrows against the policy's cash surrender value to pay the overdue premium, keeping the coverage in force until the cash value is exhausted." },
  { topic: "Life Insurance", question: "What is the 'Extended Term Insurance' non-forfeiture option?", options: ["Extending the term of a 10-year policy", "Using the policy's cash value to buy a single-premium term policy for the same death benefit, lasting as long as the cash value can fund it", "Adding a spouse to the policy", "Borrowing against the death benefit"], answer: "Using the policy's cash value to buy a single-premium term policy for the same death benefit, lasting as long as the cash value can fund it", explanation: "If a client stops paying premiums on a whole life policy, this option uses the built-up cash to keep the exact same death benefit alive for a limited number of years." },
  { topic: "Life Insurance", question: "When a policyholder takes a policy loan against their Whole Life insurance, what is the tax consequence?", options: ["It is always 100% tax-free", "It may trigger a taxable disposition if the loan amount exceeds the policy's Adjusted Cost Basis (ACB)", "It is taxed as a capital gain", "It reduces their RRSP room"], answer: "It may trigger a taxable disposition if the loan amount exceeds the policy's Adjusted Cost Basis (ACB)", explanation: "The CRA treats policy loans as an advance of the policy proceeds. If you borrow more than what you've paid in (the ACB), the excess is taxed as income." },
  { topic: "Life Insurance", question: "If a business buys Key Person life insurance on its top salesperson, are the premiums tax-deductible?", options: ["Yes, 100% deductible", "No, premiums for key person insurance are generally not tax-deductible", "Yes, if the employee owns the policy", "Only if the company goes bankrupt"], answer: "No, premiums for key person insurance are generally not tax-deductible", explanation: "Because the death benefit will be received tax-free by the corporation, the CRA does not allow the corporation to deduct the premiums as a business expense." },
  { topic: "Life Insurance", question: "In a 'Criss-Cross' Buy-Sell agreement for two business partners (A and B), who owns the policies?", options: ["The Corporation owns both", "Partner A owns a policy on Partner B, and Partner B owns a policy on Partner A", "They own policies on themselves", "The bank owns the policies"], answer: "Partner A owns a policy on Partner B, and Partner B owns a policy on Partner A", explanation: "This ensures that if Partner A dies, Partner B receives the tax-free death benefit directly to buy Partner A's shares from their estate." },
  { topic: "Life Insurance", question: "If a client names a registered charity as the beneficiary of their life insurance policy, what is the tax benefit upon death?", options: ["The premiums are refunded", "The client's estate receives a charitable donation tax receipt for the amount of the death benefit paid to the charity", "The charity pays the estate tax", "The death benefit is doubled"], answer: "The client's estate receives a charitable donation tax receipt for the amount of the death benefit paid to the charity", explanation: "This is a powerful estate planning tool. The massive tax receipt can be used to offset taxes owed on the deceased's final tax return (like capital gains on a cottage)." },
  { topic: "Life Insurance", question: "What is a 'T-100' (Term to 100) policy?", options: ["A term policy that expires at age 100", "Permanent life insurance that provides a level premium and death benefit to age 100, but typically has little to no cash surrender value", "A policy that costs $100 a month", "A 100-year investment bond"], answer: "Permanent life insurance that provides a level premium and death benefit to age 100, but typically has little to no cash surrender value", explanation: "It is designed purely for estate preservation (paying the death benefit) without the high cost of building an internal cash value like Whole Life." },
  { topic: "Life Insurance", question: "Under Universal Life, what is Yearly Renewable Term (YRT) Cost of Insurance?", options: ["A fixed cost for life", "The internal mortality cost deducted from the investment account, which increases every single year as the insured gets older", "A cost that decreases over time", "A flat fee"], answer: "The internal mortality cost deducted from the investment account, which increases every single year as the insured gets older", explanation: "YRT is cheap in the early years but becomes exponentially expensive in the later years, potentially eating away all the investment growth if not properly funded." },
  { topic: "Life Insurance", question: "If an applicant misstates their sex on a life insurance application (e.g., stating female instead of male to get a lower rate), the insurer will:", options: ["Cancel the policy for fraud", "Adjust the death benefit to the amount the premiums paid would have purchased for the correct sex", "Double the premium", "Ignore it"], answer: "Adjust the death benefit to the amount the premiums paid would have purchased for the correct sex", explanation: "Like misstatement of age, misstatement of sex does not void the policy. The insurer simply recalculates the math at the time of claim." },
  { topic: "Life Insurance", question: "Who is protected by the 'Preferred Beneficiary' class for creditor protection under the Insurance Act?", options: ["A business partner", "A spouse, child, grandchild, or parent of the life insured", "A bank", "A sibling"], answer: "A spouse, child, grandchild, or parent of the life insured", explanation: "Naming a 'preferred class' beneficiary immediately shields the life insurance policy (and its cash value) from the policyowner's creditors in most provinces." },

  // --- BATCH 3: ADVANCED A&S & GROUP BENEFITS ---
  { topic: "Accident & Sickness", question: "To qualify for CPP Disability benefits, the disability must be defined as:", options: ["Any condition lasting 3 months", "Severe and prolonged, preventing the person from working at any job on a regular basis", "A workplace injury only", "A partial loss of income"], answer: "Severe and prolonged, preventing the person from working at any job on a regular basis", explanation: "CPP Disability is extremely difficult to qualify for. 'Severe' means incapable of pursuing any regular occupation. 'Prolonged' means long-term or terminal." },
  { topic: "Accident & Sickness", question: "In Group Long Term Disability (LTD), what does the transition from 'Own Occupation' to 'Any Occupation' usually occur?", options: ["After 30 days", "Never, it stays Own Occ forever", "Typically after 24 months of disability", "At age 65"], answer: "Typically after 24 months of disability", explanation: "Most group LTD plans protect your specific job for 2 years. After that, if you are well enough to do *any* job suited to your education, they cut off benefits." },
  { topic: "Accident & Sickness", question: "How are premiums and benefits treated for Business Overhead Expense (BOE) insurance?", options: ["Premiums are not deductible; benefits are tax-free", "Premiums are tax-deductible as a business expense; benefits received are taxable as business income", "Both are tax-free", "It depends on the company structure"], answer: "Premiums are tax-deductible as a business expense; benefits received are taxable as business income", explanation: "Because BOE benefits are used to pay tax-deductible business expenses (like rent and salaries), it creates a net-zero tax effect for the business." },
  { topic: "Accident & Sickness", question: "What is a 'Recurrent Disability' provision?", options: ["A policy for recurring colds", "If the insured returns to work but suffers a relapse of the exact same disability within a specified time (e.g., 6 months), they do not have to serve a new elimination period", "A penalty for getting sick twice", "A reduction in benefits"], answer: "If the insured returns to work but suffers a relapse of the exact same disability within a specified time (e.g., 6 months), they do not have to serve a new elimination period", explanation: "This encourages disabled people to try returning to work without the fear of starting their 90-day unpaid waiting period all over again if they fail." },
  { topic: "Accident & Sickness", question: "Under Group Health Insurance, the 'Birthday Rule' is used for Coordination of Benefits for dependent children. How does it work?", options: ["The child uses the policy of the youngest parent", "The primary plan is the one belonging to the parent whose birthday falls earliest in the calendar year (month and day)", "The child gets a bonus on their birthday", "The father's plan is always primary"], answer: "The primary plan is the one belonging to the parent whose birthday falls earliest in the calendar year (month and day)", explanation: "If Mom's birthday is Feb 10 and Dad's is Aug 20, Mom's plan pays first for the kids' dental work." },
  { topic: "Accident & Sickness", question: "A Critical Illness policy typically includes a 'Moratorium Period' for cancer. What does this mean?", options: ["Cancer is never covered", "If cancer is diagnosed within the first 90 days of the policy being in force, the claim is denied and the policy may be cancelled/refunded", "The payout takes 90 days to process", "It pays double for cancer"], answer: "If cancer is diagnosed within the first 90 days of the policy being in force, the claim is denied and the policy may be cancelled/refunded", explanation: "This is an anti-selection tool to prevent people from buying the policy because they found a lump and are waiting on biopsy results." },
  { topic: "Accident & Sickness", question: "Employment Insurance (EI) Sickness Benefits typically provide coverage for a maximum of:", options: ["15 or 26 weeks, depending on current federal legislation", "2 years", "Until age 65", "52 weeks"], answer: "15 or 26 weeks, depending on current federal legislation", explanation: "EI sickness is strictly a short-term gap measure. It is designed to cover the standard 90-to-120 day elimination period before personal LTD kicks in." },
  { topic: "Accident & Sickness", question: "What is the 'Conversion Privilege' in a Group Life or Health plan?", options: ["Changing from family to single coverage", "The right of a departing employee to convert their group coverage to an individual policy without providing medical evidence of insurability", "Converting life to disability", "Getting a cash refund"], answer: "The right of a departing employee to convert their group coverage to an individual policy without providing medical evidence of insurability", explanation: "If an employee gets cancer and is fired, they can convert their group life policy to a personal one within 31 days so their family isn't left uninsured." },
  { topic: "Accident & Sickness", question: "A disability policy with a 'Cost of Living Adjustment' (COLA) rider will:", options: ["Pay for the insured's groceries", "Increase the monthly benefit payout each year while the insured is on claim, tying it to inflation (CPI)", "Increase the premium", "Pay the insured's mortgage"], answer: "Increase the monthly benefit payout each year while the insured is on claim, tying it to inflation (CPI)", explanation: "A $4,000/month benefit bought today will have very little purchasing power in 20 years. COLA protects the disabled person from inflation." },
  { topic: "Accident & Sickness", question: "In Travel Medical Insurance, what does the 'Stability Clause' refer to?", options: ["The plane must be stable", "Pre-existing medical conditions are only covered if there has been no change in symptoms, medication, or treatment for a set period (e.g., 90 days) prior to departure", "The insured must be financially stable", "The length of the trip"], answer: "Pre-existing medical conditions are only covered if there has been no change in symptoms, medication, or treatment for a set period (e.g., 90 days) prior to departure", explanation: "If a doctor increases a client's blood pressure medication 2 weeks before a trip to Florida, that condition is no longer 'stable' and will be excluded." },

  // --- BATCH 3: RRSP, RRIF & PENSIONS ---
  { topic: "Segregated Funds", question: "At what age must a Canadian collapse their Registered Retirement Savings Plan (RRSP)?", options: ["Age 65", "By December 31st of the year they turn 71", "Age 55", "There is no limit"], answer: "By December 31st of the year they turn 71", explanation: "At age 71, the RRSP must be cashed out, used to buy an annuity, or (most commonly) converted into a Registered Retirement Income Fund (RRIF)." },
  { topic: "Segregated Funds", question: "What is the primary rule of a Registered Retirement Income Fund (RRIF)?", options: ["You can no longer invest in stocks", "You must withdraw a government-mandated minimum percentage every year, which is fully taxable as income", "You can only withdraw 10%", "It is completely tax-free"], answer: "You must withdraw a government-mandated minimum percentage every year, which is fully taxable as income", explanation: "The government let you defer taxes in your RRSP for decades. The RRIF minimum withdrawal is their way of finally collecting those taxes." },
  { topic: "Segregated Funds", question: "In a Spousal RRSP, what is the '3-Year Attribution Rule'?", options: ["You must stay married for 3 years", "If the receiving spouse withdraws money within 3 calendar years of the contributing spouse's last deposit, the withdrawal is taxed in the contributing spouse's hands", "The money is locked for 3 years", "The government matches the contribution for 3 years"], answer: "If the receiving spouse withdraws money within 3 calendar years of the contributing spouse's last deposit, the withdrawal is taxed in the contributing spouse's hands", explanation: "This prevents a high-income earner from dumping $20k into a Spousal RRSP in December and having the low-income spouse withdraw it at a lower tax bracket in January." },
  { topic: "Segregated Funds", question: "What is a Pension Adjustment (PA)?", options: ["A bonus paid to retirees", "It reduces an individual's RRSP contribution room for the following year based on the value of the pension benefits they earned in their employer's registered pension plan", "An increase in CPP", "A tax penalty"], answer: "It reduces an individual's RRSP contribution room for the following year based on the value of the pension benefits they earned in their employer's registered pension plan", explanation: "The CRA ensures fairness. If you have a generous corporate pension, you are allowed less personal RRSP room than someone without a pension." },
  { topic: "Segregated Funds", question: "A Locked-in Retirement Account (LIRA) is created when:", options: ["You owe the CRA money", "An employee leaves a company and transfers their vested funds out of the employer's registered pension plan", "You buy a house", "You declare bankruptcy"], answer: "An employee leaves a company and transfers their vested funds out of the employer's registered pension plan", explanation: "Pension money is legally 'locked in' to ensure it is actually used for retirement income. It cannot be cashed out in a lump sum like a regular RRSP." },
  { topic: "Segregated Funds", question: "What is a 'Joint and Last Survivor Annuity'?", options: ["An annuity that pays out to a group of friends", "An annuity based on two lives (usually spouses) that continues paying until the second person dies", "A life insurance policy", "An annuity that stops paying when the first person dies"], answer: "An annuity based on two lives (usually spouses) that continues paying until the second person dies", explanation: "It ensures the surviving spouse continues to receive a guaranteed income stream, though often at a slightly reduced rate (e.g., 66% of the original)." },
  { topic: "Segregated Funds", question: "If a client withdraws $10,000 from their RRSP before retirement, how is it handled?", options: ["It is tax-free", "The financial institution immediately deducts a withholding tax, and the full $10,000 is added to the client's taxable income for the year", "They pay a 50% penalty", "They lose their RRSP room forever, but it's not taxed"], answer: "The financial institution immediately deducts a withholding tax, and the full $10,000 is added to the client's taxable income for the year", explanation: "Early withdrawals are heavily taxed, and unlike a TFSA, you permanently lose the contribution room you just used." },
  { topic: "Segregated Funds", question: "When an annuitant dies, how does a Segregated Fund bypass probate?", options: ["It is written into the will", "Because it is an insurance contract, if a named beneficiary (other than the estate) is listed, the money pays directly to them, avoiding the courts", "It is put in a trust", "The government waives it"], answer: "Because it is an insurance contract, if a named beneficiary (other than the estate) is listed, the money pays directly to them, avoiding the courts", explanation: "Bypassing the estate saves 1-2% in probate fees and ensures the beneficiary gets the money in weeks, rather than months or years." },
  { topic: "Segregated Funds", question: "What is a 'Deferred Annuity'?", options: ["An annuity that was denied", "The client pays a premium now, but the guaranteed income stream doesn't start until a specified date in the future (e.g., age 65)", "An annuity for deferred taxes", "An annuity that pays out backwards"], answer: "The client pays a premium now, but the guaranteed income stream doesn't start until a specified date in the future (e.g., age 65)", explanation: "During the 'deferral period', the money accumulates interest. At the specified date, it converts into a payout annuity." },
  { topic: "Segregated Funds", question: "How are dividends generated within an RRSP taxed?", options: ["As capital gains", "As eligible dividends", "They are entirely tax-sheltered while inside the RRSP, but taxed as 100% regular income when eventually withdrawn", "They are tax-free forever"], answer: "They are entirely tax-sheltered while inside the RRSP, but taxed as 100% regular income when eventually withdrawn", explanation: "RRSPs do not preserve the preferential tax treatment of Canadian dividends or capital gains. Every dollar pulled out of an RRSP is taxed as ordinary income." },

  // --- BATCH 3: ADVANCED ETHICS & COMPLIANCE ---
  { topic: "Ethics & Legal", question: "If an agent suspects a client is using a Universal Life policy to launder money, FINTRAC requires them to file a:", options: ["Large Cash Transaction Report", "Suspicious Transaction Report (STR) as soon as practicable, without tipping off the client", "Police report", "CRA tax audit"], answer: "Suspicious Transaction Report (STR) as soon as practicable, without tipping off the client", explanation: "Tipping off a money launderer that you are reporting them is a criminal offense under FINTRAC." },
  { topic: "Ethics & Legal", question: "Can a life insurance agent act as the Power of Attorney (POA) for their client?", options: ["Yes, it is highly recommended", "Generally no, as it creates a severe conflict of interest where the agent could authorize trades that earn themselves a commission", "Only for segregated funds", "Yes, if they are not related"], answer: "Generally no, as it creates a severe conflict of interest where the agent could authorize trades that earn themselves a commission", explanation: "Regulators heavily scrutinize or outright ban agents holding POA over clients unless the client is an immediate family member." },
  { topic: "Ethics & Legal", question: "What is the purpose of a 'Needs Analysis' before selling a life insurance policy?", options: ["To find out the client's bank account number", "To objectively document the client's financial situation, debts, and goals to ensure the recommended product is truly suitable", "To calculate the agent's commission", "To speed up underwriting"], answer: "To objectively document the client's financial situation, debts, and goals to ensure the recommended product is truly suitable", explanation: "Provincial regulators require a documented Needs Analysis to prove the agent gave suitable advice, protecting the client from being oversold." },
  { topic: "Ethics & Legal", question: "When an agent delivers a new life insurance policy to a client, they should obtain a:", options: ["Cash tip", "Delivery Receipt, proving the exact date the client received the contract to start the 10-day Free Look period", "Medical exam", "Letter of Direction"], answer: "Delivery Receipt, proving the exact date the client received the contract to start the 10-day Free Look period", explanation: "Without a signed delivery receipt, the client could argue years later that they never received the policy and demand a full refund." },
  { topic: "Ethics & Legal", question: "What is 'Coercion' in the insurance industry?", options: ["Offering a multi-line discount", "Using intimidation, threats, or undue pressure to force a client to buy a policy or cancel an existing one", "Sending weekly emails", "Explaining the risks of not having insurance"], answer: "Using intimidation, threats, or undue pressure to force a client to buy a policy or cancel an existing one", explanation: "Coercion is a severe ethical violation that strips the client of their free will to make financial decisions." },
  { topic: "Ethics & Legal", question: "If a life agent wants to share their commission with a mortgage broker who referred a client, they:", options: ["Can do it via e-transfer", "Cannot do it, as sharing life insurance commissions with unlicensed individuals is strictly prohibited", "Must write a formal contract", "Can only give 10%"], answer: "Cannot do it, as sharing life insurance commissions with unlicensed individuals is strictly prohibited", explanation: "Commission splitting is only legal between two agents who are both actively licensed in the exact same jurisdiction for the same class of insurance." },
  { topic: "Ethics & Legal", question: "If a client wants to replace a Whole Life policy they have held for 15 years with a new Term policy, the agent must:", options: ["Do it immediately to save them money", "Complete a Life Insurance Replacement Declaration (LIRD) explaining the loss of cash value, new suicide clauses, and older age pricing", "Refuse the request", "Shred the old policy"], answer: "Complete a Life Insurance Replacement Declaration (LIRD) explaining the loss of cash value, new suicide clauses, and older age pricing", explanation: "Replacing a 15-year-old permanent policy is almost always detrimental to the client. The LIRD ensures full, transparent disclosure of the consequences." },
  { topic: "Ethics & Legal", question: "What does 'Holding Out' mean in insurance regulation?", options: ["Waiting for a better price", "How an agent presents themselves to the public (e.g., business cards, websites) which must exactly match their licensed name and approved operating name", "Keeping a client's money", "Refusing to sell a policy"], answer: "How an agent presents themselves to the public (e.g., business cards, websites) which must exactly match their licensed name and approved operating name", explanation: "You cannot legally be licensed as 'John Smith' and print business cards calling yourself 'The Life Insurance King of Toronto' without regulatory approval." },
  { topic: "Ethics & Legal", question: "Fraud vs Misrepresentation: What is the key difference?", options: ["Fraud is verbal; misrepresentation is written", "Fraud requires deliberate, intentional deception for financial gain; misrepresentation can be an innocent or careless mistake", "There is no difference", "Fraud only applies to agents"], answer: "Fraud requires deliberate, intentional deception for financial gain; misrepresentation can be an innocent or careless mistake", explanation: "If you honestly forget you took blood pressure pills 5 years ago, it's misrepresentation. If you actively hide a cancer diagnosis to get coverage, it's fraud." },
  { topic: "Ethics & Legal", question: "Why do provincial regulators require life agents to carry Errors & Omissions (E&O) insurance?", options: ["To protect the insurance company", "To ensure that if an agent makes a negligent mistake that financially ruins a client, there are funds available to compensate the consumer", "To pay for the agent's legal fees in criminal cases", "To cover stolen laptops"], answer: "To ensure that if an agent makes a negligent mistake that financially ruins a client, there are funds available to compensate the consumer", explanation: "E&O is consumer protection. If an agent forgets to file a critical form and the widow loses a $1M death benefit, the E&O policy pays the widow." }
];
